import{_ as a,o as n,c as e,ak as p}from"./chunks/framework.DwHlt8HN.js";const o=JSON.parse('{"title":"云原生概念：容器、微服务、不可变基础设施、声明式 API","description":"","frontmatter":{},"headers":[],"relativePath":"devops/k8s/cloud-native.md","filePath":"devops/k8s/cloud-native.md","lastUpdated":1774334277000}'),i={name:"devops/k8s/cloud-native.md"};function l(r,s,t,c,d,b){return n(),e("div",null,[...s[0]||(s[0]=[p(`<h1 id="云原生概念-容器、微服务、不可变基础设施、声明式-api" tabindex="-1">云原生概念：容器、微服务、不可变基础设施、声明式 API <a class="header-anchor" href="#云原生概念-容器、微服务、不可变基础设施、声明式-api" aria-label="Permalink to “云原生概念：容器、微服务、不可变基础设施、声明式 API”">​</a></h1><p>「云原生」——这个词你一定听过无数遍了。但它到底是什么意思？为什么所有云厂商都在提它？</p><p>云原生不是「把应用跑在云服务器上」这么简单。它是一套完整的技术体系和文化理念，代表了构建和运行软件的新方式。</p><h2 id="云原生的四个核心特征" tabindex="-1">云原生的四个核心特征 <a class="header-anchor" href="#云原生的四个核心特征" aria-label="Permalink to “云原生的四个核心特征”">​</a></h2><p>CNCF（云原生计算基金会）对云原生的定义包含四个核心特征：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                     云原生四要素                            │</span></span>
<span class="line"><span>│                                                             │</span></span>
<span class="line"><span>│  ┌─────────────┐  ┌─────────────┐                         │</span></span>
<span class="line"><span>│  │   容器化     │  │   微服务     │                        │</span></span>
<span class="line"><span>│  │  Container   │  │  Microservice │                       │</span></span>
<span class="line"><span>│  └─────────────┘  └─────────────┘                         │</span></span>
<span class="line"><span>│                                                             │</span></span>
<span class="line"><span>│  ┌─────────────┐  ┌─────────────┐                         │</span></span>
<span class="line"><span>│  │ 不可变基础  │  │  声明式 API  │                        │</span></span>
<span class="line"><span>│  │   设施      │  │Declarative API│                        │</span></span>
<span class="line"><span>│  └─────────────┘  └─────────────┘                         │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h3 id="_1-容器化-标准化的打包格式" tabindex="-1">1. 容器化：标准化的打包格式 <a class="header-anchor" href="#_1-容器化-标准化的打包格式" aria-label="Permalink to “1. 容器化：标准化的打包格式”">​</a></h3><p>容器把应用及其所有依赖打包成一个标准化的镜像。无论在开发机、测试环境还是生产环境，这个镜像都是完全一致的。</p><p>这解决了「在我机器上能跑」的古老难题——<strong>Docker 解决了环境不一致的问题，K8s 解决了容器编排的问题</strong>。</p><div class="language-dockerfile line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 前后对比：没有容器化 vs 容器化</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 传统部署：应用 + JDK + 配置文件 + 系统依赖 ← 在不同机器上可能不一致</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 容器部署：一个镜像 = 应用 + JDK + 配置文件 + 依赖 ← 处处一致</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="_2-微服务-拆分与自治" tabindex="-1">2. 微服务：拆分与自治 <a class="header-anchor" href="#_2-微服务-拆分与自治" aria-label="Permalink to “2. 微服务：拆分与自治”">​</a></h3><p>微服务把一个巨大的单体应用拆分成一组小型、独立的服务，每个服务运行在自己的进程中，围绕业务能力组织，可以独立部署、独立扩展、独立演进。</p><table tabindex="0"><thead><tr><th>对比维度</th><th>单体架构</th><th>微服务架构</th></tr></thead><tbody><tr><td>部署</td><td>整体部署</td><td>独立部署</td></tr><tr><td>扩展</td><td>整体扩展</td><td>按需扩展</td></tr><tr><td>故障隔离</td><td>一挂全挂</td><td>单服务故障不影响其他</td></tr><tr><td>技术选型</td><td>统一</td><td>每个服务独立</td></tr><tr><td>团队协作</td><td>强耦合</td><td>自治团队</td></tr><tr><td>复杂度</td><td>初期低，后期高</td><td>初期高，后期可控</td></tr></tbody></table><p>微服务不是银弹——它解决了组织扩展性问题（大型团队如何高效协作），但引入了分布式系统的复杂度（服务间通信、分布式事务、服务治理）。</p><h3 id="_3-不可变基础设施-重建而非修改" tabindex="-1">3. 不可变基础设施：重建而非修改 <a class="header-anchor" href="#_3-不可变基础设施-重建而非修改" aria-label="Permalink to “3. 不可变基础设施：重建而非修改”">​</a></h3><p>传统运维思维是「修改」——服务器出问题了，登上去改配置、打补丁。<strong>不可变基础设施</strong>的思维是「重建」——任何变更都通过重新构建来实现，不修改任何正在运行的实例。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>传统思维（可变基础设施）：</span></span>
<span class="line"><span>  服务器 → 修改配置 → 重新加载服务 → 配置漂移问题</span></span>
<span class="line"><span>  问题：修改历史不可追溯，服务器之间配置不一致</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不可变基础设施：</span></span>
<span class="line"><span>  服务器配置（代码） → 构建镜像 → 部署新实例 → 销毁旧实例</span></span>
<span class="line"><span>  优势：任何变更都有版本历史，所有实例完全一致</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>在 K8s 中，这意味着：</p><ul><li>不直接 <code>kubectl exec</code> 进容器修改配置</li><li>配置通过 ConfigMap/Secret 注入，不修改容器</li><li>镜像更新通过滚动部署实现，不修改已有 Pod</li></ul><h3 id="_4-声明式-api-描述目标-而非过程" tabindex="-1">4. 声明式 API：描述目标，而非过程 <a class="header-anchor" href="#_4-声明式-api-描述目标-而非过程" aria-label="Permalink to “4. 声明式 API：描述目标，而非过程”">​</a></h3><p>传统运维是<strong>指令式</strong>的：「先做 A，再做 B，然后检查 C」。声明式 API 是：「我想要的状态是 X，你负责让它达到 X」。</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 声明式：告诉 K8s 你想要什么</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  replicas</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  selector</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    matchLabels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nginx</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># K8s 负责达成这个目标：</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → 发现只有 2 个 Pod → 自动创建第 3 个</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → 发现有 Pod 挂了 → 自动重新调度</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → 发现有节点挂了 → 自动迁移 Pod 到其他节点</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>声明式 API 的核心优势是<strong>自愈</strong>和<strong>幂等</strong>——系统会自动消除实际状态和期望状态之间的差异。</p><h2 id="云原生的技术生态" tabindex="-1">云原生的技术生态 <a class="header-anchor" href="#云原生的技术生态" aria-label="Permalink to “云原生的技术生态”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>容器运行时层</span></span>
<span class="line"><span>  └── containerd / cri-o / Docker</span></span>
<span class="line"><span></span></span>
<span class="line"><span>容器编排层</span></span>
<span class="line"><span>  └── Kubernetes（事实标准）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>服务网格层</span></span>
<span class="line"><span>  └── Istio / Linkerd / Envoy</span></span>
<span class="line"><span></span></span>
<span class="line"><span>可观测性层</span></span>
<span class="line"><span>  └── Prometheus + Grafana（监控）</span></span>
<span class="line"><span>      ELK / Loki（日志）</span></span>
<span class="line"><span>      Jaeger / Zipkin（链路追踪）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CI/CD 层</span></span>
<span class="line"><span>  └── ArgoCD / Tekton / GitHub Actions</span></span>
<span class="line"><span></span></span>
<span class="line"><span>服务治理层</span></span>
<span class="line"><span>  └── Spring Cloud / gRPC / OpenTelemetry</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><h2 id="云原生落地的常见误区" tabindex="-1">云原生落地的常见误区 <a class="header-anchor" href="#云原生落地的常见误区" aria-label="Permalink to “云原生落地的常见误区”">​</a></h2><h3 id="误区一-微服务就是越小越好" tabindex="-1">误区一：微服务就是越小越好 <a class="header-anchor" href="#误区一-微服务就是越小越好" aria-label="Permalink to “误区一：微服务就是越小越好”">​</a></h3><p>很多团队把微服务拆成了「纳米服务」——一个用户登录拆成 5 个服务，一个订单查询拆成 10 个服务。结果是：调用链爆炸、延迟增加、运维成本翻倍。</p><p><strong>正确的做法</strong>：按业务边界拆分，按团队规模验证（两个披萨原则）。如果拆分后反而更复杂，说明拆分粒度不对。</p><h3 id="误区二-上-k8s-就是云原生" tabindex="-1">误区二：上 K8s 就是云原生 <a class="header-anchor" href="#误区二-上-k8s-就是云原生" aria-label="Permalink to “误区二：上 K8s 就是云原生”">​</a></h3><p>K8s 是云原生的重要基础设施，但<strong>上了 K8s 不等于云原生</strong>。如果只是把原来的应用原封不动地搬到 K8s 里，继续用虚拟机时代的思维方式管理它，并没有真正发挥云原生的价值。</p><p>真正的云原生改造：</p><ul><li>12-Factor App：配置外部化、无状态、日志结构化</li><li>容器化：镜像构建标准化、镜像大小优化</li><li>可观测性：指标 + 日志 + 链路追踪</li><li>自动化：CI/CD 全流程自动化</li></ul><h3 id="误区三-全面推翻重来" tabindex="-1">误区三：全面推翻重来 <a class="header-anchor" href="#误区三-全面推翻重来" aria-label="Permalink to “误区三：全面推翻重来”">​</a></h3><p>很多团队对云原生趋之若鹜，试图一次性把整个系统全部云原生化。结果：</p><ul><li>迁移周期太长，业务价值迟迟无法交付</li><li>团队学习曲线陡峭，踩坑无数</li><li>遇到问题后无法回滚</li></ul><p><strong>正确的做法</strong>：Strangler Fig 模式——新旧系统并行，逐步将流量从旧系统迁移到新系统，而不是一刀切。</p><h2 id="云原生时代的-devops" tabindex="-1">云原生时代的 DevOps <a class="header-anchor" href="#云原生时代的-devops" aria-label="Permalink to “云原生时代的 DevOps”">​</a></h2><p>云原生改变了 DevOps 的含义：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>传统 DevOps：</span></span>
<span class="line"><span>  Dev（开发） ←→ Ops（运维）</span></span>
<span class="line"><span>  边界：Dev 交付代码，Ops 负责部署</span></span>
<span class="line"><span></span></span>
<span class="line"><span>云原生 DevOps：</span></span>
<span class="line"><span>  开发者全流程负责</span></span>
<span class="line"><span>  代码 → 容器镜像 → 部署配置 → 监控告警 → 扩缩容</span></span>
<span class="line"><span>  Dev 和 Ops 的边界变成了：</span></span>
<span class="line"><span>  - 开发者负责：代码 + 镜像 + Helm Chart + 监控配置</span></span>
<span class="line"><span>  - SRE/平台负责：集群、网络、存储、安全基线</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="面试追问方向" tabindex="-1">面试追问方向 <a class="header-anchor" href="#面试追问方向" aria-label="Permalink to “面试追问方向”">​</a></h2><ul><li>云原生的四个特征中，哪个是你认为最核心的？为什么？</li><li>12-Factor App 是云原生应用的黄金标准，说说你熟悉的框架是怎么实践这些原则的？</li><li>微服务拆分有哪些维度？CQRS 和 DDD 在微服务设计中扮演什么角色？</li><li>为什么说 Kubernetes 是云原生时代的操作系统？</li></ul><blockquote><p>云原生不是一个技术标准，而是一种做事方式。理解它的核心理念，比记住某个框架的 API 重要得多。</p></blockquote>`,43)])])}const k=a(i,[["render",l]]);export{o as __pageData,k as default};
